if (! function_exists('topic_research')) {
    function topic_research($topic, $hn_results = null, $wikipedia = null, $fetch_articles = null, $include_content = null, $timeout = null, $timeout_per_source = null)
    {
        // Multi-Source Topic Research Tool
        // Orchestrates: Hacker News search + Wikipedia summary + Web article extraction

        $timeout = min(30, max(5, $timeout_per_source ?? $timeout ?? 15));
        $topic = trim($topic ?? '');
        $hnResults = $hn_results ?? 5;
        $includeWikipedia = $wikipedia ?? true;
        $fetchArticles = $fetch_articles ?? false;
        $includeContent = $include_content ?? false;

        if (empty($topic)) {
            return ['success' => false, 'error' => 'Research topic is required.', 'topic' => $topic];
        }

        try {
            $report = [
                'success' => true,
                'topic' => $topic,
                'sources_queried' => 0,
                'sources_ok' => 0,
                'results' => [],
            ];

            // === SOURCE 1: Hacker News via Algolia ===
            if ($hnResults > 0) {
                $report['sources_queried']++;
                $hnOk = false;
                $hnStories = [];

                try {
                    $params = http_build_query([
                        'query' => $topic,
                        'tags' => 'story',
                        'hitsPerPage' => min(20, max(1, $hnResults)),
                    ]);
                    $hnUrl = 'https://hn.algolia.com/api/v1/search?' . $params;

                    $ctx = stream_context_create([
                        'http' => ['timeout' => $timeout, 'method' => 'GET', 'header' => "User-Agent: TopicResearch/1.0\r\nAccept: application/json\r\n"],
                        'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                    ]);

                    $hnResponse = @file_get_contents($hnUrl, false, $ctx);

                    if ($hnResponse !== false) {
                        $hnData = json_decode($hnResponse, true);
                        if ($hnData !== null && isset($hnData['hits']) && is_array($hnData['hits'])) {
                            $hnOk = true;
                            $count = 0;
                            foreach ($hnData['hits'] as $hit) {
                                if ($count >= $hnResults) break;
                                $story = [
                                    'title' => $hit['title'] ?? '(no title)',
                                    'url' => $hit['url'] ?? null,
                                    'hn_url' => 'https://news.ycombinator.com/item?id=' . ($hit['objectID'] ?? ''),
                                    'points' => $hit['points'] ?? 0,
                                    'num_comments' => $hit['num_comments'] ?? 0,
                                    'author' => $hit['author'] ?? '',
                                    'date' => $hit['created_at'] ?? '',
                                ];
                                if ($includeContent && !empty($hit['story_text'])) {
                                    $story['excerpt'] = strip_tags(mb_substr($hit['story_text'], 0, 1000));
                                }
                                $hnStories[] = $story;
                                $count++;
                            }
                        }
                    }
                } catch (\Exception $e) {
                    // HN error handled gracefully
                }

                $report['results']['hacker_news'] = [
                    'available' => $hnOk,
                    'stories_returned' => count($hnStories),
                    'stories' => $hnStories,
                ];
                if ($hnOk) $report['sources_ok']++;
            }

            // === SOURCE 2: Wikipedia ===
            if ($includeWikipedia) {
                $report['sources_queried']++;
                $wikiOk = false;
                $wikiResult = null;

                try {
                    $wikiTopic = str_replace(' ', '_', ucfirst(strtolower($topic)));
                    $wikiUrl = 'https://en.wikipedia.org/api/rest_v1/page/summary/' . urlencode($wikiTopic);

                    $ctx = stream_context_create([
                        'http' => ['timeout' => $timeout, 'method' => 'GET', 'header' => "User-Agent: TopicResearch/1.0\r\nAccept: application/json\r\n"],
                        'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                    ]);

                    $wikiResponse = @file_get_contents($wikiUrl, false, $ctx);

                    if ($wikiResponse !== false) {
                        $wikiData = json_decode($wikiResponse, true);
                        // Check for redirect
                        if (isset($wikiData['type']) && $wikiData['type'] === 'https://mediawiki.org/wiki/Special:MyLanguage/Extension:Math') {
                            // This is a special page, skip
                        }
                        if ($wikiData !== null && !empty($wikiData['extract'])) {
                            $wikiOk = true;
                            $wikiResult = [
                                'title' => $wikiData['title'] ?? $topic,
                                'extract' => $wikiData['extract'] ?? '',
                                'description' => $wikiData['description'] ?? '',
                                'url' => $wikiData['content_urls']['desktop']['page'] ?? "https://en.wikipedia.org/wiki/" . urlencode($topic),
                                'thumbnail' => $wikiData['thumbnail']['source'] ?? null,
                            ];
                        }
                    }

                    // Fallback: try exact topic
                    if (!$wikiOk) {
                        $wikiUrl2 = 'https://en.wikipedia.org/api/rest_v1/page/summary/' . urlencode($topic);
                        $wikiResponse2 = @file_get_contents($wikiUrl2, false, $ctx);
                        if ($wikiResponse2 !== false) {
                            $wikiData2 = json_decode($wikiResponse2, true);
                            if ($wikiData2 !== null && !empty($wikiData2['extract'])) {
                                $wikiOk = true;
                                $wikiResult = [
                                    'title' => $wikiData2['title'] ?? $topic,
                                    'extract' => $wikiData2['extract'] ?? '',
                                    'description' => $wikiData2['description'] ?? '',
                                    'url' => $wikiData2['content_urls']['desktop']['page'] ?? "https://en.wikipedia.org/wiki/" . urlencode($topic),
                                    'thumbnail' => $wikiData2['thumbnail']['source'] ?? null,
                                ];
                            }
                        }
                    }
                } catch (\Exception $e) {
                    // Wikipedia error handled gracefully
                }

                $report['results']['wikipedia'] = [
                    'available' => $wikiOk,
                    'result' => $wikiResult,
                ];
                if ($wikiOk) $report['sources_ok']++;
            }

            // === SOURCE 3: Fetch article content from top HN results ===
            if ($fetchArticles && !empty($report['results']['hacker_news']['stories'])) {
                $fetched = 0;
                $stories = &$report['results']['hacker_news']['stories'];
                foreach ($stories as &$story) {
                    if ($fetched >= 2) break;
                    if (empty($story['url'])) continue;

                    try {
                        $ctx = stream_context_create([
                            'http' => [
                                'timeout' => $timeout,
                                'method' => 'GET',
                                'header' => "User-Agent: Mozilla/5.0 (compatible; TopicResearch/1.0)\r\nAccept: text/html,application/xhtml+xml\r\n",
                                'ignore_errors' => true,
                            ],
                            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                        ]);

                        $pageContent = @file_get_contents($story['url'], false, $ctx);
                        if ($pageContent !== false) {
                            libxml_use_internal_errors(true);
                            $dom = new DOMDocument();
                            $dom->loadHTML(mb_substr($pageContent, 0, 500000), LIBXML_NOWARNING | LIBXML_NOERROR);
                            libxml_clear_errors();
                            $xpath = new DOMXPath($dom);
                            foreach (['//script', '//style', '//nav', '//header', '//footer'] as $query) {
                                $nodes = $xpath->query($query);
                                foreach ($nodes as $node) {
                                    try { $node->parentNode->removeChild($node); } catch (\Exception $e) {}
                                }
                            }
                            $main = $xpath->query('//main|//article|//div[@role="main"]|//div[@class="content"]|//div[@id="content"]');
                            $textNode = null;
                            if ($main->length > 0) {
                                $textNode = $main->item(0);
                            } else {
                                $body = $xpath->query('//body');
                                if ($body->length > 0) $textNode = $body->item(0);
                            }
                            if ($textNode) {
                                $text = trim(preg_replace('/\s+/', ' ', $textNode->textContent));
                                if (strlen($text) > 100) {
                                    $story['article_excerpt'] = mb_substr($text, 0, 3000);
                                    $fetched++;
                                }
                            }
                        }
                    } catch (\Exception $e) {
                        // Skip silently
                    }
                }
                unset($story);

                $report['results']['articles_fetched'] = $fetched;
            }

            return $report;

        } catch (\Exception $e) {
            return ['success' => false, 'error' => $e->getMessage(), 'topic' => $topic];
        }
    }
